// Feedback Prism — purple/gold painting with RGB split
speed = 0.5

// ---- audio (smoothed envelopes) ----
AUDIO.bins = 6; AUDIO.smooth = 0.78; AUDIO.gain = 50; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

const rampMask = () => Math.min(1, time * 0.8);

// --- LAYER 1: Noise painting base (o1)
// purple/gold: noise tinted purple, osc tinted gold
noise(2.5, () => 0.06 + Math.sin(time * 0.15) * 0.02)
  .color(0.6, 0.1, 1.0)
  .blend(
    osc(8, 0.15, 4).color(1.0, 0.75, 0.15),
    0.75
  )
  .modulate(noise(1.8, 0.5), () => 0.08 + low() * 0.012)
  .saturate(() => 1.2 + mid() * 0.2)
  .out(o1)

// --- LAYER 2: Secondary texture — voronoi/osc cross (o2)
voronoi(() => 8 + 3 * Math.sin(time * 0.08), 0.03, 3)
  .color(0.8, 0.3, 0.9)
  .modulate(osc(12, 0.08, 2), 0.06)
  .blend(
    osc(3, 0.2, 1).rotate(() => time * 0.02).color(0.9, 0.7, 0.2),
    0.3
  )
  .brightness(0.03)
  .contrast(1.02)
  .out(o2)

// --- COMPOSITE: Layers + heavy self-feedback (o3)
src(o1)
  .blend(src(o2), 0.25)
  .blend(src(o3), () => rampMask() * (0.82 + low() * 0.04))
  .modulate(noise(1.4, 0.6), () => 0.09 + low() * 0.01)
  .add(noise(8000, 0.7), 0.02)
  .saturate(() => 1.15 + mid() * 0.18)
  .contrast(() => 1.01 + high() * 0.02)
  .brightness(0.008)
  .out(o3)

// --- Write composite to o0 for chromatic processing
src(o3)
  .colorama(() => 0.003 + amp() * 0.008)
  .hue(() => Math.sin(time * 0.03) * 0.02)
  .out(o0)

// --- CHROMATIC ABERRATION: Full RGB channel split
// Wider splits than usual for prismatic effect
src(o0).r()
  .scrollX(() => 0.003 + low() * 0.002)
  .scrollY(() => 0.0015 + mid() * 0.001)
  .color(1.15, 0.08, 0.06)
  .add(
    src(o0).g()
    .scrollX(() => -(0.002 + low() * 0.0012))
    .scrollY(() => -(0.001 + mid() * 0.0008))
    .color(0.12, 1.05, 0.18),
    0.9
  )
  .add(
    src(o0).b()
    .scrollX(() => 0.001 * Math.sin(time * 0.3))
    .scrollY(() => 0.002 + amp() * 0.0012)
    .color(0.06, 0.1, 1.1),
    0.9
  )
  // post-processing
  .saturate(() => 1.35 + mid() * 0.2)
  .colorama(() => 0.001 + amp() * 0.003)
  .contrast(1.04)
  .brightness(0.015)
  .out();
